        <input type="text" id="trackInput" placeholder="Ex: FRKT-ABCD-1234" autocomplete="off" autocorrect="off" spellcheck="false"
          style="width:100%;padding:13px 16px;border:1.5px solid #e5e7eb;border-radius:8px;font-size:.95rem;font-family:'Nunito',sans-serif;text-align:center;letter-spacing:.08em;text-transform:uppercase;outline:none;transition:border-color .2s;background:#f9fafb;"
