          onblur="this.style.borderColor='#e5e7eb';this.style.boxShadow='none'"
          onkeydown="if(event.key==='Enter')document.getElementById('trackBtn').click()">
        <button id="trackBtn" onclick="trackOrder()"
          style="width:100%;margin-top:12px;padding:14px;background:#f5c518;color:#1a1d26;border:none;border-radius:8px;font-size:.95rem;font-weight:800;font-family:'Nunito',sans-serif;cursor:pointer;transition:all .2s;display:flex;align-items:center;justify-content:center;gap:8px;"
          onmouseover="this.style.background='#EAB308'" onmouseout="this.style.background='#f5c518'">
          <i class="fa-solid fa-magnifying-glass"></i> Rastrear
        </button>
        <div id="trackResult" style="display:none;margin-top:16px;padding:16px;border-radius:10px;text-align:left;font-size:.9rem;"></div>
