  <script>
    function trackOrder() {
      const code = document.getElementById('trackInput').value.trim();
      const resultEl = document.getElementById('trackResult');
      if (!code) {
        resultEl.style.display = 'block';
        resultEl.style.background = '#FEF2F2';
        resultEl.style.border = '1.5px solid #FCA5A5';
        resultEl.style.color = '#B91C1C';
        resultEl.innerHTML = '<i class="fa-solid fa-triangle-exclamation"></i> Introduz um código de rastreio válido.';
        return;
      }
      resultEl.style.display = 'block';
      resultEl.style.background = '#F0FDF4';
      resultEl.style.border = '1.5px solid #86EFAC';
      resultEl.style.color = '#166534';
      resultEl.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> A procurar encomenda…';
      // Redireciona para o tracknfast com o código
      setTimeout(function() {
        window.open('https://tracknfast.com/track/' + encodeURIComponent(code), '_blank');
        resultEl.innerHTML = '<i class="fa-solid fa-circle-check"></i> Página de rastreio aberta numa nova aba.';
      }, 800);
    }
  </script>

