    let cart = [];
    let currentCategory = "Todos";
    let currentAge = "Todas";

    function filterCategory(cat) {
      currentCategory = cat;
      document.querySelectorAll('.filter-btn').forEach(b => b.classList.toggle('active', b.textContent === cat));
      document.getElementById('contentTitle').textContent = cat === "Todos" ? "Todos os Produtos" : cat;
      applyFilters();
    }

    function filterAge(age) {
      currentAge = age;
      document.querySelectorAll('.age-btn').forEach(b => b.classList.toggle('active', b.textContent === age));
      applyFilters();
    }

    function applyFilters() {
      const cards = document.querySelectorAll('.product-card');
      let count = 0;
      cards.forEach(card => {
        const catMatch = currentCategory === "Todos" || card.dataset.category === currentCategory;
        const ageMatch = currentAge === "Todas" || card.dataset.age === currentAge;
        const show = catMatch && ageMatch;
        card.style.display = show ? '' : 'none';
        if (show) count++;
      });
      document.getElementById('productCount').textContent = count + ' produtos';
    }

    function openModal(id) {
      const p = products.find(x => x.id === id);
      if (!p) return;
      document.getElementById('modalImg').src = p.img;
      document.getElementById('modalImg').alt = p.name;
      document.getElementById('modalCat').textContent = p.cat;
      document.getElementById('modalName').textContent = p.name;
      document.getElementById('modalDesc').textContent = p.desc;
      document.getElementById('modalPieces').innerHTML = '<i class="fa-solid fa-box" style="color:#DC2626"></i> ' + p.pieces + ' peças';
      document.getElementById('modalAge').innerHTML = '<i class="fa-solid fa-baby" style="color:#F59E0B"></i> Idade: ' + p.age;
      const op = document.getElementById('modalOldPrice');
      op.textContent = p.oldPrice ? '€' + p.oldPrice.toFixed(2) : '';
      op.style.display = p.oldPrice ? '' : 'none';
      document.getElementById('modalPrice').textContent = '€' + p.price.toFixed(2);
      document.getElementById('modalCartBtn').onclick = () => { addToCart(id); closeModal(); };
      
      // Tracking ViewContent (TikTok only)
      if (window.ttq) {
        ttq.track('ViewContent', {
          contents: [{
            content_id: String(p.id),
            content_name: p.name,
            content_type: 'product'
          }],
          value: p.price,
          currency: 'EUR',
          event_id: (window.checkout_id || 'CH') + '-view-' + String(p.id)
        });
      }

      document.getElementById('modal').classList.add('open');
    }

    function closeModal() {
      document.getElementById('modal').classList.remove('open');
    }

    function addToCart(id) {
      const p = products.find(x => x.id === id);
      if (!p) return;

      // Se já existe no carrinho, incrementa quantidade; senão adiciona novo item
      const existing = cart.find(x => x.id === id);
      if (existing) {
        existing.quantity = (existing.quantity || 1) + 1;
      } else {
        cart.push({ ...p, quantity: 1 });
      }

      if (window.ttq) {
        ttq.track('AddToCart', {
          contents: [{
            content_id: String(p.id),
            content_name: p.name,
            content_type: 'product',
            quantity: 1,
            price: p.price
          }],
          value: p.price,
          currency: 'EUR',
          event_id: (window.checkout_id || 'CH') + '-cart-' + String(p.id) + '-' + Date.now()
        });
      }

      updateCart();
      pulseCartFab();
      showToast('Produto adicionado no carrinho!');
    }

    // Dispara animação de pulso no FAB do carrinho
    function pulseCartFab() {
      const fab = document.getElementById('cartFab');
      if (!fab) return;
      fab.classList.remove('pulsing');
      void fab.offsetWidth; // força reflow pra reiniciar a animação
      fab.classList.add('pulsing');
      setTimeout(() => fab.classList.remove('pulsing'), 600);
    }
    // ── Checkout (página separada checkout.php) ──────────────

    function finalizarCompra() {
      if (cart.length === 0) {
        alert("Escolha um produto primeiro!");
        return;
      }

      const checkout_id = 'CH-' + Date.now() + Math.random().toString(36).substr(2, 9);

      // Salva estado do carrinho para o checkout.php consumir
      try {
        sessionStorage.setItem('esco_checkout_state', JSON.stringify({
          cart: cart.map(i => ({
            id: i.id,
            name: i.name,
            price: i.price,
            oldPrice: (typeof i.oldPrice === 'number' && !isNaN(i.oldPrice)) ? i.oldPrice : null,
            quantity: i.quantity,
            img: i.img,
            cat: i.cat || ''
          })),
          checkout_id: checkout_id
        }));
      } catch (_) {}

      // Redireciona para a página de checkout dedicada
      window.location.href = 'checkout.php';
    }

    // ── (checkout movido para checkout.php) ──────────────────

    function updateCart() {
      const container = document.getElementById('cartItems');
      const footer = document.getElementById('cartFooter');
      const countEl = document.getElementById('cartCount');
      const totalCount = cart.reduce((s, i) => s + i.quantity, 0);
      countEl.textContent = totalCount;
      countEl.style.display = totalCount > 0 ? 'flex' : 'none';

      // Sincroniza badge do FAB (gota d'água flutuante)
      const fabBadge = document.getElementById('cartFabBadge');
      if (fabBadge) {
        fabBadge.textContent = totalCount;
        fabBadge.classList.toggle('hidden', totalCount === 0);
      }

      if (cart.length === 0) {
        container.innerHTML = '<p class="cart-empty">Seu carrinho está vazio <i class="fa-solid fa-futbol"></i></p>';
        footer.style.display = 'none';
        return;
      }

      footer.style.display = '';
      const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);
      document.getElementById('cartTotal').textContent = '€' + total.toFixed(2);

      container.innerHTML = cart.map(item => `
    <div class="cart-item">
      <img src="${item.img}" alt="${item.name}">
      <div class="cart-item-info">
        <h4>${item.name}</h4>
        <div class="price">€${item.price.toFixed(2)}</div>
        <div class="cart-qty">
          <button onclick="changeQty(${item.id},-1)">−</button>
          <span>${item.quantity}</span>
          <button onclick="changeQty(${item.id},1)">+</button>
          <button class="cart-remove" onclick="removeItem(${item.id})"><i class="fa-solid fa-trash" style="color:#DC2626"></i></button>
        </div>
      </div>
    </div>
  `).join('');
    }

    function changeQty(id, delta) {
      const item = cart.find(x => x.id === id);
      if (!item) return;
      item.quantity += delta;
      if (item.quantity <= 0) cart = cart.filter(x => x.id !== id);
      updateCart();
    }

    function removeItem(id) {
      cart = cart.filter(x => x.id !== id);
      updateCart();
    }

    function toggleCart() {
      document.getElementById('cartDrawer').classList.toggle('open');
      document.getElementById('cartOverlay').classList.toggle('open');
    }

    function showToast(msg) {
      const t = document.getElementById('toast');
      t.innerHTML = '<i class="fa-solid fa-circle-check" style="color:#16A34A"></i> ' + msg;
      t.classList.add('show');
      setTimeout(() => t.classList.remove('show'), 2500);
    }

    // Init
    document.getElementById('cartCount').style.display = 'none';
  </script>
  <script>
    let tempo = 10 * 60; // 10 minutos

    function atualizarTimer() {
      let dias = Math.floor(tempo / (24 * 60 * 60));
      let horas = Math.floor((tempo % (24 * 60 * 60)) / 3600);
      let minutos = Math.floor((tempo % 3600) / 60);
      let segundos = tempo % 60;

      document.getElementById("days").textContent = dias;
      document.getElementById("hours").textContent = String(horas).padStart(2, '0');
      document.getElementById("minutes").textContent = String(minutos).padStart(2, '0');
      document.getElementById("seconds").textContent = String(segundos).padStart(2, '0');

      if (tempo > 0) {
        tempo--;
      }
    }

    setInterval(atualizarTimer, 1000);
    atualizarTimer();
  </script>


