    .cart-fab {
      position: fixed;
      bottom: 24px;
      right: 24px;
      width: 64px;
      height: 64px;
      border-radius: 50%;
      background: linear-gradient(135deg, #FACC15 0%, #EAB308 100%);
      border: none;
      cursor: pointer;
      box-shadow: 0 10px 28px rgba(234, 179, 8, 0.45), 0 4px 10px rgba(0,0,0,0.12);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 9998;
      transition: transform 0.22s ease, box-shadow 0.22s ease;
    }
    /* Ponta da gota apontando para a esquerda */
    .cart-fab::before {
      content: '';
      position: absolute;
      left: -9px;
      top: 50%;
      transform: translateY(-50%);
      width: 0;
      height: 0;
      border-top: 11px solid transparent;
      border-bottom: 11px solid transparent;
      border-right: 13px solid #EAB308;
      filter: drop-shadow(-2px 2px 3px rgba(234, 179, 8, 0.35));
    }
    .cart-fab:hover {
