      justify-content: center;
      border: 2.5px solid #ffffff;
      box-shadow: 0 3px 8px rgba(37, 99, 235, 0.5);
      font-family: 'Nunito', sans-serif;
      line-height: 1;
    }
    .cart-fab-badge.hidden { display: none; }
    @keyframes cart-fab-pulse {
      0%   { transform: scale(1); box-shadow: 0 10px 28px rgba(234, 179, 8, 0.45), 0 4px 10px rgba(0,0,0,0.12); }
      30%  { transform: scale(1.28); box-shadow: 0 0 0 12px rgba(250, 204, 21, 0.35), 0 10px 28px rgba(234, 179, 8, 0.55); }
      60%  { transform: scale(0.94); }
      100% { transform: scale(1); box-shadow: 0 10px 28px rgba(234, 179, 8, 0.45), 0 4px 10px rgba(0,0,0,0.12); }
    }
    .cart-fab.pulsing {
      animation: cart-fab-pulse 0.55s ease-out;
    }
    @keyframes cart-fab-badge-pop {
      0%   { transform: scale(1); background: #2563EB; }
      40%  { transform: scale(1.45); background: #1D4ED8; }
      100% { transform: scale(1); background: #2563EB; }
    }
    .cart-fab.pulsing .cart-fab-badge {
      animation: cart-fab-badge-pop 0.55s ease-out;
    }
    @media (max-width: 640px) {
      .cart-fab { width: 58px; height: 58px; bottom: 18px; right: 18px; }
      .cart-fab .cart-fab-svg { width: 25px; height: 30px; }
    }
  </style>
  <button class="cart-fab" id="cartFab" onclick="toggleCart()" aria-label="Abrir carrinho">
    <svg class="cart-fab-svg" viewBox="0 0 16 20" aria-hidden="true" xmlns="http://www.w3.org/2000/svg"><g fill="#1a1d26" fill-rule="evenodd"><path d="M4 3.512v5.804c0 .377.349.684.779.684.43 0 .779-.307.779-.684V3.512C5.558 2.33 6.653 1.368 8 1.368c1.347 0 2.442.962 2.442 2.144v5.804c0 .377.35.684.78.684.43 0 .778-.307.778-.684V3.512C12 1.575 10.206 0 8 0S4 1.575 4 3.512z"/><path d="M2.46 6.33c-.269 0-.489.194-.5.441L1.435 18.19a.436.436 0 00.131.332.52.52 0 00.348.149h12.151c.276 0 .501-.207.501-.462l-.525-11.436c-.011-.248-.23-.442-.5-.442H2.46zM14.448 20l-12.974-.001a1.591 1.591 0 01-1.064-.462 1.357 1.357 0 01-.408-1.03L.56 6.372C.595 5.602 1.277 5 2.11 5h11.78c.835 0 1.516.602 1.551 1.372l.56 12.197c0 .789-.697 1.431-1.553 1.431z"/></g></svg>
    <span class="cart-fab-badge hidden" id="cartFabBadge">0</span>
  </button>
</body>

